import { Component, signal, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink, Router } from '@angular/router';
import { ReactiveFormsModule, FormBuilder, Validators, FormArray, FormGroup } from '@angular/forms';
import { Customer, Product } from '../../core/models';

@Component({
  selector: 'app-so-new',
  standalone: true,
  imports: [CommonModule, RouterLink, ReactiveFormsModule],
  templateUrl: './so-new.component.html',
})
export class SoNewComponent {
  private fb = inject(FormBuilder);
  private router = inject(Router);

  customers = signal<Customer[]>([
    { id: 'c1', name: 'Northwind Traders' },
    { id: 'c2', name: 'Contoso Ltd' },
    { id: 'c3', name: 'Fabrikam Inc' },
  ]);

  products = signal<Product[]>([
    { id: 'p1', sku: 'STL-001', name: 'Steel Bolt M8', cost: 0.45, price: 1.20, onHand: 1200 },
    { id: 'p3', sku: 'PIP-050', name: 'PVC Pipe 50mm', cost: 3.20, price: 7.50, onHand: 340 },
    { id: 'p8', sku: 'SEN-200', name: 'Proximity Sensor', cost: 22.50, price: 49.00, onHand: 140 },
  ]);

  form = this.fb.group({
    customer: ['', Validators.required],
    lines: this.fb.array([this.newLine()]),
  });

  get lines(): FormArray {
    return this.form.get('lines') as FormArray;
  }

  private newLine(): FormGroup {
    return this.fb.group({
      product: ['', Validators.required],
      qty: [1, [Validators.required, Validators.min(1)]],
    });
  }

  addLine(): void {
    this.lines.push(this.newLine());
  }

  removeLine(i: number): void {
    this.lines.removeAt(i);
  }

  productFor(id: string | null | undefined): Product | undefined {
    return this.products().find((p) => p.id === id);
  }

  estimatedTotal(): number {
    return this.lines.controls.reduce((sum, ctrl) => {
      const product = this.productFor(ctrl.get('product')?.value);
      const qty = Number(ctrl.get('qty')?.value) || 0;
      return sum + (product ? product.price * qty : 0);
    }, 0);
  }

  submit(): void {
    if (this.form.invalid) return;
    // Mockup: persistence is added by the service_agent stage.
    this.router.navigate(['/sales-orders']);
  }
}
